import { create } from 'zustand';

export interface Layer {
  id: string;
  name: string;
  type: 'image' | 'annotation' | 'ai_result';
  visible: boolean;
  opacity: number;
  locked: boolean;
  order: number;
}

export interface ImageFilter {
  id: string;
  type: 'sharpen' | 'gaussian_blur' | 'median' | 'sobel' | 'canny' | 'histogram_eq' | 'brightness' | 'contrast' | 'saturation';
  name: string;
  enabled: boolean;
  params: Record<string, number>;
}

export type EditorTool = 'select' | 'brush' | 'eraser' | 'text' | 'shape';

interface EditorState {
  layers: Layer[];
  activeLayerId: string | null;
  filters: ImageFilter[];
  activeTool: EditorTool;
  brushSize: number;
  brushColor: string;
}

interface EditorActions {
  // Layer actions
  addLayer: (layer: Layer) => void;
  removeLayer: (id: string) => void;
  updateLayer: (id: string, updates: Partial<Layer>) => void;
  reorderLayers: (fromIndex: number, toIndex: number) => void;
  setActiveLayer: (id: string | null) => void;
  toggleLayerVisibility: (id: string) => void;
  toggleLayerLock: (id: string) => void;
  setLayerOpacity: (id: string, opacity: number) => void;

  // Filter actions
  addFilter: (filter: ImageFilter) => void;
  removeFilter: (id: string) => void;
  updateFilter: (id: string, updates: Partial<ImageFilter>) => void;
  toggleFilter: (id: string) => void;
  setFilterParam: (id: string, param: string, value: number) => void;
  resetFilters: () => void;

  // Tool actions
  setActiveTool: (tool: EditorTool) => void;
  setBrushSize: (size: number) => void;
  setBrushColor: (color: string) => void;
}

const defaultFilters: ImageFilter[] = [
  { id: 'brightness', type: 'brightness', name: '亮度', enabled: false, params: { value: 0 } },
  { id: 'contrast', type: 'contrast', name: '对比度', enabled: false, params: { value: 0 } },
  { id: 'saturation', type: 'saturation', name: '饱和度', enabled: false, params: { value: 0 } },
];

export const useEditorStore = create<EditorState & EditorActions>((set) => ({
  layers: [],
  activeLayerId: null,
  filters: [...defaultFilters],
  activeTool: 'select',
  brushSize: 5,
  brushColor: '#ff0000',

  // Layer actions
  addLayer: (layer) =>
    set((state) => ({
      layers: [...state.layers, layer].sort((a, b) => a.order - b.order),
      activeLayerId: layer.id,
    })),

  removeLayer: (id) =>
    set((state) => ({
      layers: state.layers.filter((l) => l.id !== id),
      activeLayerId: state.activeLayerId === id ? null : state.activeLayerId,
    })),

  updateLayer: (id, updates) =>
    set((state) => ({
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, ...updates } : l
      ),
    })),

  reorderLayers: (fromIndex, toIndex) =>
    set((state) => {
      const newLayers = [...state.layers];
      const [moved] = newLayers.splice(fromIndex, 1);
      newLayers.splice(toIndex, 0, moved);
      return {
        layers: newLayers.map((l, i) => ({ ...l, order: i })),
      };
    }),

  setActiveLayer: (id) => set({ activeLayerId: id }),

  toggleLayerVisibility: (id) =>
    set((state) => ({
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, visible: !l.visible } : l
      ),
    })),

  toggleLayerLock: (id) =>
    set((state) => ({
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, locked: !l.locked } : l
      ),
    })),

  setLayerOpacity: (id, opacity) =>
    set((state) => ({
      layers: state.layers.map((l) =>
        l.id === id ? { ...l, opacity: Math.max(0, Math.min(1, opacity)) } : l
      ),
    })),

  // Filter actions
  addFilter: (filter) =>
    set((state) => ({
      filters: [...state.filters, filter],
    })),

  removeFilter: (id) =>
    set((state) => ({
      filters: state.filters.filter((f) => f.id !== id),
    })),

  updateFilter: (id, updates) =>
    set((state) => ({
      filters: state.filters.map((f) =>
        f.id === id ? { ...f, ...updates } : f
      ),
    })),

  toggleFilter: (id) =>
    set((state) => ({
      filters: state.filters.map((f) =>
        f.id === id ? { ...f, enabled: !f.enabled } : f
      ),
    })),

  setFilterParam: (id, param, value) =>
    set((state) => ({
      filters: state.filters.map((f) =>
        f.id === id
          ? { ...f, params: { ...f.params, [param]: value } }
          : f
      ),
    })),

  resetFilters: () => set({ filters: [...defaultFilters] }),

  // Tool actions
  setActiveTool: (tool) => set({ activeTool: tool }),
  setBrushSize: (size) => set({ brushSize: Math.max(1, Math.min(100, size)) }),
  setBrushColor: (color) => set({ brushColor: color }),
}));

/**
 * Image processing utilities using Canvas API
 */

export interface ProcessedImageData {
  data: Uint8ClampedArray;
  width: number;
  height: number;
}

/**
 * Apply brightness adjustment
 */
export function applyBrightness(imageData: ImageData, value: number): ImageData {
  const data = new Uint8ClampedArray(imageData.data);
  const factor = (value / 100) * 255;

  for (let i = 0; i < data.length; i += 4) {
    data[i] = Math.min(255, Math.max(0, data[i] + factor));
    data[i + 1] = Math.min(255, Math.max(0, data[i + 1] + factor));
    data[i + 2] = Math.min(255, Math.max(0, data[i + 2] + factor));
  }

  return new ImageData(data, imageData.width, imageData.height);
}

/**
 * Apply contrast adjustment
 */
export function applyContrast(imageData: ImageData, value: number): ImageData {
  const data = new Uint8ClampedArray(imageData.data);
  const factor = (259 * (value + 255)) / (255 * (259 - value));

  for (let i = 0; i < data.length; i += 4) {
    data[i] = Math.min(255, Math.max(0, factor * (data[i] - 128) + 128));
    data[i + 1] = Math.min(255, Math.max(0, factor * (data[i + 1] - 128) + 128));
    data[i + 2] = Math.min(255, Math.max(0, factor * (data[i + 2] - 128) + 128));
  }

  return new ImageData(data, imageData.width, imageData.height);
}

/**
 * Apply saturation adjustment
 */
export function applySaturation(imageData: ImageData, value: number): ImageData {
  const data = new Uint8ClampedArray(imageData.data);
  const factor = 1 + value / 100;

  for (let i = 0; i < data.length; i += 4) {
    const gray = 0.2989 * data[i] + 0.5870 * data[i + 1] + 0.1140 * data[i + 2];
    data[i] = Math.min(255, Math.max(0, gray + factor * (data[i] - gray)));
    data[i + 1] = Math.min(255, Math.max(0, gray + factor * (data[i + 1] - gray)));
    data[i + 2] = Math.min(255, Math.max(0, gray + factor * (data[i + 2] - gray)));
  }

  return new ImageData(data, imageData.width, imageData.height);
}

/**
 * Apply sharpen filter
 */
export function applySharpen(imageData: ImageData, strength: number = 1): ImageData {
  const kernel = [
    0, -1, 0,
    -1, 5 * strength, -1,
    0, -1, 0,
  ];
  return applyConvolution(imageData, kernel, 3);
}

/**
 * Apply Gaussian blur
 */
export function applyGaussianBlur(imageData: ImageData, radius: number = 1): ImageData {
  const size = Math.ceil(radius * 2) * 2 + 1;
  const kernel = generateGaussianKernel(size, radius);
  return applyConvolution(imageData, kernel, size);
}

/**
 * Apply median filter (noise reduction)
 */
export function applyMedianFilter(imageData: ImageData, radius: number = 1): ImageData {
  const data = new Uint8ClampedArray(imageData.data);
  const width = imageData.width;
  const height = imageData.height;
  const size = radius * 2 + 1;

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const neighbors: number[][] = [[], [], []];

      for (let ky = -radius; ky <= radius; ky++) {
        for (let kx = -radius; kx <= radius; kx++) {
          const px = Math.min(width - 1, Math.max(0, x + kx));
          const py = Math.min(height - 1, Math.max(0, y + ky));
          const idx = (py * width + px) * 4;

          neighbors[0].push(data[idx]);
          neighbors[1].push(data[idx + 1]);
          neighbors[2].push(data[idx + 2]);
        }
      }

      const idx = (y * width + x) * 4;
      data[idx] = median(neighbors[0]);
      data[idx + 1] = median(neighbors[1]);
      data[idx + 2] = median(neighbors[2]);
    }
  }

  return new ImageData(data, width, height);
}

/**
 * Apply Sobel edge detection
 */
export function applySobel(imageData: ImageData): ImageData {
  const grayscale = toGrayscale(imageData);
  const width = grayscale.width;
  const height = grayscale.height;
  const data = new Uint8ClampedArray(width * height * 4);

  const kernelX = [-1, 0, 1, -2, 0, 2, -1, 0, 1];
  const kernelY = [-1, -2, -1, 0, 0, 0, 1, 2, 1];

  for (let y = 1; y < height - 1; y++) {
    for (let x = 1; x < width - 1; x++) {
      let gx = 0;
      let gy = 0;

      for (let ky = -1; ky <= 1; ky++) {
        for (let kx = -1; kx <= 1; kx++) {
          const idx = ((y + ky) * width + (x + kx)) * 4;
          const val = grayscale.data[idx];
          const ki = (ky + 1) * 3 + (kx + 1);
          gx += val * kernelX[ki];
          gy += val * kernelY[ki];
        }
      }

      const magnitude = Math.min(255, Math.sqrt(gx * gx + gy * gy));
      const idx = (y * width + x) * 4;
      data[idx] = data[idx + 1] = data[idx + 2] = magnitude;
      data[idx + 3] = 255;
    }
  }

  return new ImageData(data, width, height);
}

/**
 * Apply Canny edge detection
 */
export function applyCanny(imageData: ImageData, lowThreshold: number = 50, highThreshold: number = 150): ImageData {
  // Step 1: Gaussian blur
  const blurred = applyGaussianBlur(imageData, 1.4);

  // Step 2: Sobel
  const edges = applySobel(blurred);

  // Step 3: Non-maximum suppression and double thresholding
  const width = edges.width;
  const height = edges.height;
  const data = new Uint8ClampedArray(width * height * 4);

  for (let y = 1; y < height - 1; y++) {
    for (let x = 1; x < width - 1; x++) {
      const idx = (y * width + x) * 4;
      const val = edges.data[idx];

      if (val >= highThreshold) {
        data[idx] = data[idx + 1] = data[idx + 2] = 255;
      } else if (val >= lowThreshold) {
        // Check neighbors
        let hasStrongNeighbor = false;
        for (let ky = -1; ky <= 1; ky++) {
          for (let kx = -1; kx <= 1; kx++) {
            const nIdx = ((y + ky) * width + (x + kx)) * 4;
            if (edges.data[nIdx] >= highThreshold) {
              hasStrongNeighbor = true;
              break;
            }
          }
          if (hasStrongNeighbor) break;
        }
        if (hasStrongNeighbor) {
          data[idx] = data[idx + 1] = data[idx + 2] = 255;
        }
      }
      data[idx + 3] = 255;
    }
  }

  return new ImageData(data, width, height);
}

/**
 * Apply histogram equalization
 */
export function applyHistogramEqualization(imageData: ImageData): ImageData {
  const data = new Uint8ClampedArray(imageData.data);
  const width = imageData.width;
  const height = imageData.height;
  const totalPixels = width * height;

  // Calculate histogram for each channel
  const histograms = [
    new Array(256).fill(0),
    new Array(256).fill(0),
    new Array(256).fill(0),
  ];

  for (let i = 0; i < data.length; i += 4) {
    histograms[0][data[i]]++;
    histograms[1][data[i + 1]]++;
    histograms[2][data[i + 2]]++;
  }

  // Calculate CDF
  const cdfs = histograms.map((hist) => {
    const cdf = new Array(256);
    cdf[0] = hist[0];
    for (let i = 1; i < 256; i++) {
      cdf[i] = cdf[i - 1] + hist[i];
    }
    return cdf;
  });

  // Normalize
  const cdfMins = cdfs.map((cdf) => {
    let min = 0;
    for (let i = 0; i < 256; i++) {
      if (cdf[i] > 0) {
        min = cdf[i];
        break;
      }
    }
    return min;
  });

  // Apply equalization
  for (let i = 0; i < data.length; i += 4) {
    for (let c = 0; c < 3; c++) {
      const cdf = cdfs[c];
      const cdfMin = cdfMins[c];
      data[i + c] = Math.round(((cdf[data[i + c]] - cdfMin) / (totalPixels - cdfMin)) * 255);
    }
  }

  return new ImageData(data, width, height);
}

/**
 * Helper: Apply convolution kernel
 */
function applyConvolution(imageData: ImageData, kernel: number[], kernelSize: number): ImageData {
  const data = new Uint8ClampedArray(imageData.data);
  const width = imageData.width;
  const height = imageData.height;
  const half = Math.floor(kernelSize / 2);

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      let r = 0, g = 0, b = 0;

      for (let ky = -half; ky <= half; ky++) {
        for (let kx = -half; kx <= half; kx++) {
          const px = Math.min(width - 1, Math.max(0, x + kx));
          const py = Math.min(height - 1, Math.max(0, y + ky));
          const idx = (py * width + px) * 4;
          const ki = (ky + half) * kernelSize + (kx + half);

          r += imageData.data[idx] * kernel[ki];
          g += imageData.data[idx + 1] * kernel[ki];
          b += imageData.data[idx + 2] * kernel[ki];
        }
      }

      const idx = (y * width + x) * 4;
      data[idx] = Math.min(255, Math.max(0, r));
      data[idx + 1] = Math.min(255, Math.max(0, g));
      data[idx + 2] = Math.min(255, Math.max(0, b));
    }
  }

  return new ImageData(data, width, height);
}

/**
 * Helper: Generate Gaussian kernel
 */
function generateGaussianKernel(size: number, sigma: number): number[] {
  const kernel = new Array(size * size);
  const center = Math.floor(size / 2);
  let sum = 0;

  for (let y = 0; y < size; y++) {
    for (let x = 0; x < size; x++) {
      const dx = x - center;
      const dy = y - center;
      const value = Math.exp(-(dx * dx + dy * dy) / (2 * sigma * sigma));
      kernel[y * size + x] = value;
      sum += value;
    }
  }

  // Normalize
  for (let i = 0; i < kernel.length; i++) {
    kernel[i] /= sum;
  }

  return kernel;
}

/**
 * Helper: Convert to grayscale
 */
function toGrayscale(imageData: ImageData): ImageData {
  const data = new Uint8ClampedArray(imageData.data);

  for (let i = 0; i < data.length; i += 4) {
    const gray = 0.2989 * data[i] + 0.5870 * data[i + 1] + 0.1140 * data[i + 2];
    data[i] = data[i + 1] = data[i + 2] = gray;
  }

  return new ImageData(data, imageData.width, imageData.height);
}

/**
 * Helper: Calculate median
 */
function median(values: number[]): number {
  const sorted = [...values].sort((a, b) => a - b);
  const mid = Math.floor(sorted.length / 2);
  return sorted.length % 2 !== 0 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
}

/**
 * Apply all active filters to image data
 */
export function applyFilters(
  ctx: CanvasRenderingContext2D,
  filters: Array<{ type: string; enabled: boolean; params: Record<string, number> }>
): void {
  if (!ctx.canvas.width || !ctx.canvas.height) return;

  let imageData = ctx.getImageData(0, 0, ctx.canvas.width, ctx.canvas.height);

  for (const filter of filters) {
    if (!filter.enabled) continue;

    switch (filter.type) {
      case 'brightness':
        imageData = applyBrightness(imageData, filter.params.value || 0);
        break;
      case 'contrast':
        imageData = applyContrast(imageData, filter.params.value || 0);
        break;
      case 'saturation':
        imageData = applySaturation(imageData, filter.params.value || 0);
        break;
      case 'sharpen':
        imageData = applySharpen(imageData, filter.params.strength || 1);
        break;
      case 'gaussian_blur':
        imageData = applyGaussianBlur(imageData, filter.params.radius || 1);
        break;
      case 'median':
        imageData = applyMedianFilter(imageData, filter.params.radius || 1);
        break;
      case 'sobel':
        imageData = applySobel(imageData);
        break;
      case 'canny':
        imageData = applyCanny(imageData, filter.params.low || 50, filter.params.high || 150);
        break;
      case 'histogram_eq':
        imageData = applyHistogramEqualization(imageData);
        break;
    }
  }

  ctx.putImageData(imageData, 0, 0);
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useEditorStore, Layer } from '@/stores/editorStore';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';
import {
  Eye,
  EyeOff,
  Lock,
  Unlock,
  Trash2,
  Plus,
  GripVertical,
  Image,
  Pen,
  Cpu,
} from 'lucide-react';
import { cn } from '@/lib/utils';

interface LayerManagerProps {
  className?: string;
}

const layerTypeIcons = {
  image: Image,
  annotation: Pen,
  ai_result: Cpu,
};

const layerTypeLabels = {
  image: '图像',
  annotation: '标注',
  ai_result: 'AI结果',
};

export function LayerManager({ className }: LayerManagerProps) {
  const { t } = useTranslation();
  const {
    layers,
    activeLayerId,
    addLayer,
    removeLayer,
    updateLayer,
    reorderLayers,
    setActiveLayer,
    toggleLayerVisibility,
    toggleLayerLock,
    setLayerOpacity,
  } = useEditorStore();

  const [dragIndex, setDragIndex] = useState<number | null>(null);
  const [newLayerName, setNewLayerName] = useState('');
  const [newLayerType, setNewLayerType] = useState<Layer['type']>('annotation');

  const handleDragStart = (index: number) => {
    setDragIndex(index);
  };

  const handleDragOver = (e: React.DragEvent, index: number) => {
    e.preventDefault();
    if (dragIndex !== null && dragIndex !== index) {
      reorderLayers(dragIndex, index);
      setDragIndex(index);
    }
  };

  const handleDragEnd = () => {
    setDragIndex(null);
  };

  const handleAddLayer = () => {
    if (!newLayerName.trim()) return;

    const newLayer: Layer = {
      id: `layer-${Date.now()}`,
      name: newLayerName,
      type: newLayerType,
      visible: true,
      opacity: 1,
      locked: false,
      order: layers.length,
    };

    addLayer(newLayer);
    setNewLayerName('');
  };

  return (
    <div className={cn('space-y-4', className)}>
      <div className="flex items-center justify-between">
        <Label className="text-sm font-semibold">{t('viewer.layers')}</Label>
      </div>

      {/* Add new layer */}
      <div className="flex space-x-2">
        <Input
          value={newLayerName}
          onChange={(e) => setNewLayerName(e.target.value)}
          placeholder="图层名称"
          className="flex-1 h-8 text-xs"
          onKeyDown={(e) => e.key === 'Enter' && handleAddLayer()}
        />
        <select
          value={newLayerType}
          onChange={(e) => setNewLayerType(e.target.value as Layer['type'])}
          className="h-8 rounded border bg-background px-2 text-xs"
        >
          {Object.entries(layerTypeLabels).map(([value, label]) => (
            <option key={value} value={value}>
              {label}
            </option>
          ))}
        </select>
        <Button
          size="sm"
          onClick={handleAddLayer}
          disabled={!newLayerName.trim()}
          className="h-8 px-2"
        >
          <Plus className="h-3 w-3" />
        </Button>
      </div>

      {/* Layer list */}
      <div className="space-y-1 max-h-[300px] overflow-y-auto">
        {layers.length === 0 ? (
          <div className="text-center py-4 text-muted-foreground text-xs">
            暂无图层
          </div>
        ) : (
          [...layers]
            .sort((a, b) => b.order - a.order)
            .map((layer, index) => {
              const Icon = layerTypeIcons[layer.type];
              const isActive = layer.id === activeLayerId;

              return (
                <div
                  key={layer.id}
                  draggable
                  onDragStart={() => handleDragStart(index)}
                  onDragOver={(e) => handleDragOver(e, index)}
                  onDragEnd={handleDragEnd}
                  onClick={() => setActiveLayer(layer.id)}
                  className={cn(
                    'flex items-center space-x-2 p-2 rounded-md cursor-pointer transition-colors',
                    isActive
                      ? 'bg-primary/10 border border-primary/30'
                      : 'hover:bg-muted',
                    dragIndex === index && 'opacity-50'
                  )}
                >
                  <GripVertical className="h-3 w-3 text-muted-foreground cursor-grab" />

                  <Icon className="h-4 w-4 text-muted-foreground" />

                  <div className="flex-1 min-w-0">
                    <div className="text-sm truncate">{layer.name}</div>
                    <div className="text-xs text-muted-foreground">
                      {layerTypeLabels[layer.type]}
                    </div>
                  </div>

                  <div className="flex items-center space-x-1">
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6"
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleLayerVisibility(layer.id);
                      }}
                      title={layer.visible ? '隐藏' : '显示'}
                    >
                      {layer.visible ? (
                        <Eye className="h-3 w-3" />
                      ) : (
                        <EyeOff className="h-3 w-3 text-muted-foreground" />
                      )}
                    </Button>

                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6"
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleLayerLock(layer.id);
                      }}
                      title={layer.locked ? '解锁' : '锁定'}
                    >
                      {layer.locked ? (
                        <Lock className="h-3 w-3 text-yellow-500" />
                      ) : (
                        <Unlock className="h-3 w-3" />
                      )}
                    </Button>

                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6 text-destructive hover:text-destructive"
                      onClick={(e) => {
                        e.stopPropagation();
                        removeLayer(layer.id);
                      }}
                      title="删除"
                    >
                      <Trash2 className="h-3 w-3" />
                    </Button>
                  </div>
                </div>
              );
            })
        )}
      </div>

      {/* Opacity slider for active layer */}
      {activeLayerId && (
        <div className="pt-2 border-t">
          <div className="flex justify-between text-xs mb-1">
            <Label>透明度</Label>
            <span>{Math.round((layers.find((l) => l.id === activeLayerId)?.opacity || 1) * 100)}%</span>
          </div>
          <input
            type="range"
            className="w-full"
            min="0"
            max="100"
            value={Math.round((layers.find((l) => l.id === activeLayerId)?.opacity || 1) * 100)}
            onChange={(e) => setLayerOpacity(activeLayerId, Number(e.target.value) / 100)}
          />
        </div>
      )}
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useEditorStore, ImageFilter } from '@/stores/editorStore';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Plus, Trash2, RotateCcw } from 'lucide-react';
import { cn } from '@/lib/utils';

interface ImageFiltersProps {
  className?: string;
}

const availableFilters: Array<{
  type: ImageFilter['type'];
  name: string;
  params: Array<{ key: string; label: string; min: number; max: number; default: number }>;
}> = [
  {
    type: 'brightness',
    name: '亮度',
    params: [{ key: 'value', label: '值', min: -100, max: 100, default: 0 }],
  },
  {
    type: 'contrast',
    name: '对比度',
    params: [{ key: 'value', label: '值', min: -100, max: 100, default: 0 }],
  },
  {
    type: 'saturation',
    name: '饱和度',
    params: [{ key: 'value', label: '值', min: -100, max: 100, default: 0 }],
  },
  {
    type: 'sharpen',
    name: '锐化',
    params: [{ key: 'strength', label: '强度', min: 0, max: 5, default: 1 }],
  },
  {
    type: 'gaussian_blur',
    name: '高斯模糊',
    params: [{ key: 'radius', label: '半径', min: 1, max: 20, default: 1 }],
  },
  {
    type: 'median',
    name: '中值滤波',
    params: [{ key: 'radius', label: '半径', min: 1, max: 5, default: 1 }],
  },
  {
    type: 'sobel',
    name: 'Sobel边缘检测',
    params: [],
  },
  {
    type: 'canny',
    name: 'Canny边缘检测',
    params: [
      { key: 'low', label: '低阈值', min: 0, max: 255, default: 50 },
      { key: 'high', label: '高阈值', min: 0, max: 255, default: 150 },
    ],
  },
  {
    type: 'histogram_eq',
    name: '直方图均衡化',
    params: [],
  },
];

export function ImageFilters({ className }: ImageFiltersProps) {
  const { t } = useTranslation();
  const {
    filters,
    addFilter,
    removeFilter,
    updateFilter,
    toggleFilter,
    setFilterParam,
    resetFilters,
  } = useEditorStore();

  const [selectedFilterType, setSelectedFilterType] = useState<ImageFilter['type']>('sharpen');

  const handleAddFilter = () => {
    const filterDef = availableFilters.find((f) => f.type === selectedFilterType);
    if (!filterDef) return;

    // Check if filter already exists
    if (filters.some((f) => f.type === selectedFilterType)) {
      return;
    }

    const params: Record<string, number> = {};
    filterDef.params.forEach((p) => {
      params[p.key] = p.default;
    });

    const newFilter: ImageFilter = {
      id: `filter-${Date.now()}`,
      type: selectedFilterType,
      name: filterDef.name,
      enabled: true,
      params,
    };

    addFilter(newFilter);
  };

  const getFilterDef = (type: ImageFilter['type']) => {
    return availableFilters.find((f) => f.type === type);
  };

  return (
    <div className={cn('space-y-4', className)}>
      <div className="flex items-center justify-between">
        <Label className="text-sm font-semibold">{t('viewer.filters')}</Label>
        <Button
          variant="ghost"
          size="sm"
          onClick={resetFilters}
          className="h-7 px-2 text-xs"
        >
          <RotateCcw className="h-3 w-3 mr-1" />
          重置
        </Button>
      </div>

      {/* Add filter */}
      <div className="flex space-x-2">
        <select
          value={selectedFilterType}
          onChange={(e) => setSelectedFilterType(e.target.value as ImageFilter['type'])}
          className="flex-1 h-8 rounded border bg-background px-2 text-xs"
        >
          {availableFilters.map((f) => (
            <option
              key={f.type}
              value={f.type}
              disabled={filters.some((sf) => sf.type === f.type)}
            >
              {f.name}
            </option>
          ))}
        </select>
        <Button
          size="sm"
          onClick={handleAddFilter}
          disabled={filters.some((f) => f.type === selectedFilterType)}
          className="h-8 px-2"
        >
          <Plus className="h-3 w-3" />
        </Button>
      </div>

      {/* Active filters */}
      <div className="space-y-3 max-h-[400px] overflow-y-auto">
        {filters.length === 0 ? (
          <div className="text-center py-4 text-muted-foreground text-xs">
            暂无滤镜
          </div>
        ) : (
          filters.map((filter) => {
            const filterDef = getFilterDef(filter.type);

            return (
              <div
                key={filter.id}
                className={cn(
                  'p-3 rounded-md border transition-colors',
                  filter.enabled ? 'bg-primary/5 border-primary/20' : 'bg-muted/50'
                )}
              >
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center space-x-2">
                    <Switch
                      checked={filter.enabled}
                      onCheckedChange={() => toggleFilter(filter.id)}
                      className="scale-75"
                    />
                    <span className="text-sm font-medium">{filter.name}</span>
                  </div>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-6 w-6 text-destructive hover:text-destructive"
                    onClick={() => removeFilter(filter.id)}
                  >
                    <Trash2 className="h-3 w-3" />
                  </Button>
                </div>

                {/* Filter parameters */}
                {filterDef && filterDef.params.length > 0 && (
                  <div className="space-y-2 mt-2">
                    {filterDef.params.map((param) => (
                      <div key={param.key}>
                        <div className="flex justify-between text-xs mb-1">
                          <span className="text-muted-foreground">{param.label}</span>
                          <span>{filter.params[param.key] ?? param.default}</span>
                        </div>
                        <input
                          type="range"
                          className="w-full"
                          min={param.min}
                          max={param.max}
                          value={filter.params[param.key] ?? param.default}
                          onChange={(e) =>
                            setFilterParam(filter.id, param.key, Number(e.target.value))
                          }
                          disabled={!filter.enabled}
                        />
                      </div>
                    ))}
                  </div>
                )}
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}

